frappe.web_form.after_load = () => {
    // Code to be executed after the form loads
    console.log('Form Loaded');

    // Event registration using jQuery
    $('button[type="submit"]').on('click', () => {
        // Code to be executed when the form is submitted
        const email = frappe.web_form.get_value('email');
        console.log('email', email);

        // Call the function after a delay of 10 seconds (10,000 milliseconds)
        setTimeout(() => {
            frappe.call({
                method: 'khanal_tech_integrations.utils.purchase.vendor_Posting.User_Sent_Email',
                args: {
                    data: email,
                },
                callback: function(response) {
                    // Handle the response if needed
                    console.log('worked');
                    frappe.db.commit();

                }
            });
        }, 3000); // 1 seconds in milliseconds
    });
};
